// Rate limiting middleware (basic implementation)
const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX = 20; // max uploads per window

function rateLimiter(req, res, next) {
  const userId = req.user ? req.user.id : req.ip;
  const now = Date.now();

  if (!rateLimitMap.has(userId)) {
    rateLimitMap.set(userId, []);
  }

  const timestamps = rateLimitMap.get(userId).filter(t => now - t < RATE_LIMIT_WINDOW);
  timestamps.push(now);
  rateLimitMap.set(userId, timestamps);

  if (timestamps.length > RATE_LIMIT_MAX) {
    return res.status(429).json({ error: 'Too many upload requests. Please try again later.' });
  }

  next();
}

// Apply rate limiter to upload routes
app.use('/api/upload', rateLimiter);

// Serve static files with security headers
app.use('/uploads', (req, res, next) => {
  // Prevent path traversal
  const requestedPath = path.normalize(req.path);
  if (requestedPath.includes('..')) {
    return res.status(403).json({ error: 'Forbidden' });
  }

  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('Content-Security-Policy', "default-src 'none'; img-src 'self'");
  res.setHeader('X-Frame-Options', 'DENY');

  // Force download for non-image files
  const ext = path.extname(requestedPath).toLowerCase();
  const imageExtensions = ['.jpg', '.jpeg', '.png', '.gif'];
  if (!imageExtensions.includes(ext)) {
    res.setHeader('Content-Disposition', 'attachment');
  }

  next();
}, express.static(path.join(__dirname, 'public', 'uploads')));

